<template>
  <div>
    <h2>
      {{ brands[0].title[0].toLowerCase() + ' (' + brands.length + ')' }}
      {{ brands.length > 5 ? (opened ? 'открытый' : 'закрытый') : '' }}
      <button v-if="brands.length > 5" @click.prevent="opened = !opened">
        {{ opened ? 'закрыть' : 'раскрыть' }}
      </button>
    </h2>
    <div>
      <BrandCard
        v-for="brand in opened ? brands : brands.slice(0, 5)"
        :key="brand.id"
        :brand="brand"
      />
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent, PropType } from 'vue'
import { BrandItem } from '@/types'
import BrandCard from '@/components/BrandCard.vue'

export default defineComponent({
  name: 'TreeItem',
  components: {
    BrandCard,
  },
  data() {
    return {
      opened: false,
    }
  },
  props: {
    brands: {
      type: [] as PropType<BrandItem>,
      required: true,
    },
  },
})
</script>

