
import { defineComponent } from 'vue'
import { BrandItem } from '@/types'
import { apiStatus } from '@/constants/apiStatus'
import { apiStatusComputedFactory } from '@/helpers/apiStatusComputedFactory'
import BrandService from '@/services/BrandService'
import router from '@/router'

const { IDLE, PENDING, SUCCESS, ERROR } = apiStatus
export default defineComponent({
  name: 'CreateBrand',
  data() {
    return {
      brand: {
        title: '',
        main: true,
      } as BrandItem,
      createBrandStatus: IDLE,
    }
  },
  computed: {
    ...apiStatusComputedFactory('createBrandStatus'),
  },
  methods: {
    create_brand() {
      this.createBrandStatus = PENDING
      BrandService.createBrand(this.brand)
        .then((response) => {
          this.createBrandStatus = SUCCESS
          router.push(`/brand/${response.data._id}`) // Перенаправляем на только что созданную страницу
        })
        .catch(() => {
          this.createBrandStatus = ERROR
        })
    },
  },
})
