
import { defineComponent } from 'vue'
import { BrandItem } from '@/types'
import { apiStatus } from '@/constants/apiStatus'
import { apiStatusComputedFactory } from '@/helpers/apiStatusComputedFactory'
import BrandService from '../services/BrandService'
import router from '@/router'

const { IDLE, PENDING, SUCCESS, ERROR } = apiStatus
export default defineComponent({
  data() {
    return {
      brand: {} as BrandItem,
      is_editing: false,
      fetchBrand: IDLE,
    }
  },
  props: {
    id: {
      type: String,
      required: true,
    },
  },
  computed: {
    ...apiStatusComputedFactory('fetchBrand'),
  },
  created() {
    this.fetchBrand = PENDING
    BrandService.getBrand(this.id)
      .then((response) => {
        this.brand = response.data
        this.fetchBrand = SUCCESS
      })
      .catch(() => {
        this.fetchBrand = ERROR
      })
  },
  methods: {
    /**
     * Удаление brand
     */
    delete_brand() {
      if (confirm('Вы уверены?')) {
        this.fetchBrand = PENDING
        BrandService.deleteBrand(this.id)
          .then(() => {
            router.push('/') // Перенаправляем на главную
          })
          .catch(() => {
            router.push('/')
          })
      }
    },
    /**
     * Редактирование brand
     */
    update_brand() {
      this.fetchBrand = PENDING
      BrandService.updateBrand(this.id, {
        title: this.brand.title,
        main: this.brand.main,
      })
        .then((response) => {
          this.fetchBrand = SUCCESS
          this.brand = response.data
          this.is_editing = false
        })
        .catch(() => {
          this.fetchBrand = ERROR
        })
    },
  },
})
