<template>
  <div v-if="fetchBrandPending">Загрузка</div>
  <div v-if="fetchBrandSuccess">
    <h1>{{ brand._id }}</h1>
    <div v-if="!is_editing">
      <div>
        <span>Title:</span>
        {{ brand.title }}
      </div>
      <div>
        <span>Main:</span>
        {{ brand.main }}
      </div>
    </div>
    <div v-else>
      <div>
        <label>
          <span>Title:</span>
          <input type="text" v-model="brand.title" />
        </label>
      </div>
      <div>
        <label>
          <span>Main:</span>
          <input type="checkbox" v-model="brand.main" />
        </label>
      </div>
    </div>

    <button :class="$style.btn" @click="is_editing = !is_editing">
      <span v-if="!is_editing"> Редакировать </span>
      <span v-else> Отменить </span>
    </button>
    <button :class="$style.btn" v-show="is_editing" @click="update_brand">
      Сохранить
    </button>
    <button :class="$style.btn" @click="delete_brand">Удалить</button>
  </div>
  <div v-if="fetchBrandError">
    Ошибка загрузки данных, возможно этот объект был удален.
  </div>
</template>

<script lang="ts">
import { defineComponent } from 'vue'
import { BrandItem } from '@/types'
import { apiStatus } from '@/constants/apiStatus'
import { apiStatusComputedFactory } from '@/helpers/apiStatusComputedFactory'
import BrandService from '../services/BrandService'
import router from '@/router'

const { IDLE, PENDING, SUCCESS, ERROR } = apiStatus
export default defineComponent({
  data() {
    return {
      brand: {} as BrandItem,
      is_editing: false,
      fetchBrand: IDLE,
    }
  },
  props: {
    id: {
      type: String,
      required: true,
    },
  },
  computed: {
    ...apiStatusComputedFactory('fetchBrand'),
  },
  created() {
    this.fetchBrand = PENDING
    BrandService.getBrand(this.id)
      .then((response) => {
        this.brand = response.data
        this.fetchBrand = SUCCESS
      })
      .catch(() => {
        this.fetchBrand = ERROR
      })
  },
  methods: {
    /**
     * Удаление brand
     */
    delete_brand() {
      if (confirm('Вы уверены?')) {
        this.fetchBrand = PENDING
        BrandService.deleteBrand(this.id)
          .then(() => {
            router.push('/') // Перенаправляем на главную
          })
          .catch(() => {
            router.push('/')
          })
      }
    },
    /**
     * Редактирование brand
     */
    update_brand() {
      this.fetchBrand = PENDING
      BrandService.updateBrand(this.id, {
        title: this.brand.title,
        main: this.brand.main,
      })
        .then((response) => {
          this.fetchBrand = SUCCESS
          this.brand = response.data
          this.is_editing = false
        })
        .catch(() => {
          this.fetchBrand = ERROR
        })
    },
  },
})
</script>

<style module scoped>
.btn {
  padding: 5px;
  border: 1px solid #eeeeee;
  margin-right: 10px;
}
</style>
