
import { defineComponent } from 'vue'
import { mapMutations } from 'vuex'

export default defineComponent({
  name: 'SearchField',
  data() {
    return {
      case_sensitive: false,
      text_field: '',
      sort: 'ASC',
    }
  },
  methods: {
    ...mapMutations(['search']),
    /**
     * Смена учета регистра и выполнение фильтрации
     */
    change_sensitive() {
      this.case_sensitive = !this.case_sensitive
      this.search({
        text_field: this.text_field,
        case_sensitive: this.case_sensitive,
        sort: this.sort,
      })
    },
    /**
     * Смена порядка фильтрации и выполнение ее же
     * @param value
     */
    set_sort(value: string) {
      // Если смены не произошло
      if (this.sort === value) {
        return
      }
      this.sort = value
      this.search({
        text_field: this.text_field,
        case_sensitive: this.case_sensitive,
        sort: this.sort,
      })
    },
  },
})
