import axios from 'axios'
import { BrandItem } from '@/types'

const apiClient = axios.create({
  baseURL: 'https://recruting-test-api.herokuapp.com/api/v1',
  withCredentials: false,
  headers: {
    Accept: 'application/json',
    'Content-Type': 'application/json',
  },
})

export default {
  getBrands() {
    return apiClient.get('/brands')
  },
  getBrand(id: string) {
    return apiClient.get(`/brand/${id}`)
  },
  deleteBrand(id: string) {
    return apiClient.delete(`/brand/${id}`)
  },
  updateBrand(id: string, data: BrandItem) {
    return apiClient.put(`/brand/${id}`, data)
  },
  createBrand(data: BrandItem) {
    return apiClient.post(`/brands`, data)
  },
}
