import { BrandItem, SortType } from '@/types'

/**
 * Создаем массивы, по буквам, независимо от регистра
 * Пример:
 * input = [
 *  {title: '12'},
 *  {title: '13'},
 *  {title: 'Bbb'},
 *  {title: '14'},
 *  {title: 'aa'},
 *  {title: 'bg234b'}
 * ]
 *
 * output: [
 * [ {title: '12'}, {title: '13'}, {title: '14'} ]
 * [ {title: 'aa'} ]
 * [ {title: 'Bbb'}, {title: 'bg234b'} ]
 * ]
 *
 * @param array
 * @param sort
 */
function groupByLetter(
  array: Array<BrandItem>,
  sort: SortType
): Array<BrandItem[]> {
  let grouped_array = [] as BrandItem[][]
  // Отсортируем полученный массив
  array.sort((a: BrandItem, b: BrandItem) => {
    return a.title.localeCompare(b.title)
  })
  // Если соритровка по убыванию, переворачиваем
  if (sort === 'DESC') {
    array.reverse()
  }
  // Будем хранить текущую букву для сравнений
  let first_letter: string = ''
  // -1 потому что на первом же шаге увеличивается index
  let index: number = -1
  array.forEach((item: BrandItem) => {
    // Смотрим не сменился ли первый символ title
    if (
      first_letter.toLocaleLowerCase() === item.title[0].toLocaleLowerCase()
    ) {
      // Есть ли массив для этой буквы
      grouped_array[index].push(item)
    } else {
      // Запоминаем новую первую букву
      first_letter = item.title[0]
      index++
      // Создаем пустой массив для текущей буквы
      grouped_array[index] = []
      grouped_array[index].push(item)
    }
  })
  // Фильтруем по main
  grouped_array.forEach((item) => {
    return item.sort((a: BrandItem, b: BrandItem) =>
      a.main === b.main ? 0 : a.main ? -1 : 1
    )
  })

  return grouped_array
}

export default groupByLetter
