<template>
  <div>
    <h1>Главная</h1>
    <div v-if="fetchBrandsPending">Загрузка</div>
    <div v-if="fetchBrandsSuccess">
      <SearchField />
      <TreeItem v-for="item in brands" :brands="item" :key="item"></TreeItem>
    </div>
    <div v-if="fetchBrandsError">
      Ошибка загрузки данных, повторите попытку позже
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from 'vue'
import TreeItem from '../components/TreeItem.vue'
import SearchField from '../components/SearchField.vue'
import { mapActions, mapGetters } from 'vuex'
import { apiStatusComputedFactory } from '@/helpers/apiStatusComputedFactory'

export default defineComponent({
  name: 'TreeView',
  components: {
    TreeItem,
    SearchField,
  },
  methods: {
    ...mapActions(['FETCH_BRANDS']),
  },
  computed: {
    ...mapGetters({
      fetchBrands: 'get_fetch_brands_status',
      brands: 'get_brands',
    }),
    ...apiStatusComputedFactory('fetchBrands'),
  },
  async created() {
    await this.FETCH_BRANDS()
  },
})
</script>

<style scoped module></style>
