const upperFirst = (s: string) => {
  return s.charAt(0).toUpperCase() + s.slice(1)
}

import { apiStatus } from '@/constants/apiStatus'

/**
 * Генерируем computed property для каждого api status
 * Пример, если reactivePropertyKey = 'fetchDataStatus':
 *
 * {
 *   fetchDataStatusIdle: function() {
 *     return this['fetchDataStatus'] === 'IDLE'
 *   }
 *
 *   fetchDataStatusPending: function() {
 *     return this['fetchDataStatus'] === 'PENDING'
 *   }
 *
 *   fetchDataStatusSuccess: function() {
 *     return this['fetchDataStatus'] === 'SUCCESS'
 *   }
 *
 *   fetchDataStatusError: function() {
 *     return this['fetchDataStatus'] === 'ERROR'
 *   }
 * }
 *
 * @important - reactivePropertyKey должно быть реактивным
 *
 * @param {string[] | string} reactivePropertyKeys
 * @return {object}
 */
export const apiStatusComputedFactory = (reactivePropertyKeys: string) => {
  /**
   * Объект для хранения геттеров
   * разных API status'ов
   *
   */
  let computed = {} as any

  // Проверяем переданный аргумент на массив
  const properties: Array<string> = Array.isArray(reactivePropertyKeys)
    ? reactivePropertyKeys
    : [reactivePropertyKeys]

  for (const reactivePropertyKey of properties) {
    /**
     * Цикл по
     * IDLE, PENDING, SUCCESS, ERROR
     */
    for (const [statusKey, statusValue] of Object.entries(apiStatus)) {
      /**
       * Нормализуем
       * IDLE -> Idle
       * SUCCESS -> Success
       */
      const normalisedStatus = upperFirst(statusKey.toLowerCase())
      /**
       * Добавляем computed свойство
       */
      computed[`${reactivePropertyKey}${normalisedStatus}`] =
        function (): boolean {
          return this[reactivePropertyKey] === statusValue
        }
    }
  }
  return computed
}
