<template>
  <div>
    <input
      :class="$style.search_field"
      v-model="text_field"
      @keyup="search({ text_field, case_sensitive, sort })"
      type="text"
    />
    <div :class="$style.btns_wrapper">
      <div :class="$style.btn_wrapper">
        <button
          @click="change_sensitive"
          :class="[$style.btn, case_sensitive ? $style.active : '']"
        >
          Aa
        </button>
        <div>
          {{
            case_sensitive
              ? '(поиск с учетом регистра включен)'
              : '(поиск с учетом регистра выключен)'
          }}
        </div>
      </div>
      <div>
        <button
          @click="set_sort('ASC')"
          :class="[$style.btn, sort === 'ASC' ? $style.active : '']"
        >
          A-Z
        </button>
        <button
          @click="set_sort('DESC')"
          :class="[$style.btn, sort === 'DESC' ? $style.active : '']"
        >
          Z-A
        </button>
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from 'vue'
import { mapMutations } from 'vuex'

export default defineComponent({
  name: 'SearchField',
  data() {
    return {
      case_sensitive: false,
      text_field: '',
      sort: 'ASC',
    }
  },
  methods: {
    ...mapMutations(['search']),
    /**
     * Смена учета регистра и выполнение фильтрации
     */
    change_sensitive() {
      this.case_sensitive = !this.case_sensitive
      this.search({
        text_field: this.text_field,
        case_sensitive: this.case_sensitive,
        sort: this.sort,
      })
    },
    /**
     * Смена порядка фильтрации и выполнение ее же
     * @param value
     */
    set_sort(value: string) {
      // Если смены не произошло
      if (this.sort === value) {
        return
      }
      this.sort = value
      this.search({
        text_field: this.text_field,
        case_sensitive: this.case_sensitive,
        sort: this.sort,
      })
    },
  },
})
</script>

<style scoped module>
.search_field {
  width: 100%;
  margin-bottom: 10px;
  padding: 5px;
}

.btns_wrapper {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.btn {
  padding: 5px;
  border: 1px solid #eeeeee;
  margin-right: 10px;
}

.active {
  border-color: #42b983;
  background-color: #fff;
}

.btn_wrapper {
  display: flex;
  align-items: center;
}
</style>
