import { createStore } from 'vuex'
import { BrandItem, SortType } from '@/types'
import BrandService from '../services/BrandService'
import groupByLetter from '@/helpers/groupByLetter'
import { apiStatus } from '@/constants/apiStatus'

const { IDLE, PENDING, SUCCESS, ERROR } = apiStatus

export default createStore({
  state: {
    brands: Array<BrandItem[]>(), // Неотсортированные данные
    filtered_brands: Array<BrandItem[]>(), // Отфильтрованные данные
    fetch_brands_status: IDLE, // Статус запроса
  },
  mutations: {
    /**
     * Записываем в неотсортированные, и в фильтрованные данные
     * Ставим статус SUCCESS
     *
     * @param state
     * @param payload
     */
    set_brands: (state, payload) => {
      state.brands = groupByLetter(payload, 'ASC')
      state.filtered_brands = state.brands
      state.fetch_brands_status = SUCCESS
    },
    /**
     * Раскрываем вложенные массивы, фильтруем, и собираем снова
     *
     * @param state
     * @param payload { text_field: string; case_sensitive: boolean; sort: SortType }
     */
    search: (
      state,
      payload: { text_field: string; case_sensitive: boolean; sort: SortType }
    ) => {
      // Смотрим на учёт регистра
      if (payload.case_sensitive)
        state.filtered_brands = groupByLetter(
          state.brands
            .flat()
            .filter((item) => item.title.includes(payload.text_field)),
          payload.sort
        )
      else {
        state.filtered_brands = groupByLetter(
          state.brands
            .flat()
            .filter((item) =>
              item.title
                .toLowerCase()
                .includes(payload.text_field.toLowerCase())
            ),
          payload.sort
        )
      }
    },
    // Мутация статуса запроса
    change_fetch_brands_status: (state, payload) => {
      state.fetch_brands_status = payload
    },
  },
  actions: {
    FETCH_BRANDS: (ctx) => {
      ctx.commit('change_fetch_brands_status', PENDING)
      BrandService.getBrands()
        .then((response) => {
          ctx.commit('set_brands', response.data)
        })
        .catch(() => {
          ctx.commit('change_fetch_brands_status', ERROR)
        })
    },
  },
  getters: {
    /**
     * Возвращаем именно фильтрованный массив
     * @param state
     */
    get_brands: (state) => {
      return state.filtered_brands
    },
    /**
     * Возвращаем статус запроса
     * @param state
     */
    get_fetch_brands_status: (state) => {
      return state.fetch_brands_status
    },
  },
})
